import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../api';
import { ArrowLeft, CheckCircle, XCircle } from 'lucide-react';

const Attendance = () => {
    const { id } = useParams();
    const [employee, setEmployee] = useState(null);
    const [attendanceList, setAttendanceList] = useState([]);
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [date, setDate] = useState(new Date().toISOString().split('T')[0]);

    useEffect(() => {
        const fetchDetails = async () => {
            try {
                setLoading(true);
                const [empRes, attRes] = await Promise.all([
                    api.get(`employees/${id}/`),
                    api.get(`attendance/?employee_id=${id}`)
                ]);
                setEmployee(empRes.data);
                setAttendanceList(attRes.data);
            } catch (err) {
                console.error("Failed to fetch details", err);
            } finally {
                setLoading(false);
            }
        };
        fetchDetails();
    }, [id]);

    const markAttendance = async (status) => {
        try {
            setSubmitting(true);
            const response = await api.post('attendance/', {
                employee_id: id,
                date: date,
                status: status
            });
            setAttendanceList([...attendanceList, response.data]);
        } catch (err) {
            if (err.response && err.response.data && err.response.data.non_field_errors) {
                alert("Attendance for this date already exists.");
            } else {
                alert("Failed to mark attendance.");
            }
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) return <div className="p-8 text-center text-gray-500">Loading...</div>;
    if (!employee) return <div className="p-8 text-center text-red-500">Employee not found</div>;

    return (
        <div className="space-y-6 max-w-4xl mx-auto">
            <div className="flex items-center space-x-4 mb-6">
                <Link to="/" className="text-gray-500 hover:text-gray-900">
                    <ArrowLeft className="h-6 w-6" />
                </Link>
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">{employee.full_name}'s Attendance</h2>
                    <p className="text-sm text-gray-500">{employee.emp_id} | {employee.department}</p>
                </div>
            </div>

            <div className="bg-white shadow sm:rounded-lg mb-8 ring-1 ring-gray-200">
                <div className="px-4 py-5 sm:p-6 text-center">
                    <h3 className="text-lg font-medium leading-6 text-gray-900 mb-4">Mark Attendance</h3>
                    <div className="flex justify-center items-center space-x-4">
                        <input
                            type="date"
                            value={date}
                            onChange={(e) => setDate(e.target.value)}
                            className="block rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm py-2 px-3 border"
                        />
                        <button
                            onClick={() => markAttendance('Present')}
                            disabled={submitting}
                            className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-green-600 hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 disabled:bg-green-400"
                        >
                            <CheckCircle className="-ml-1 mr-2 h-5 w-5" />
                            Mark Present
                        </button>
                        <button
                            onClick={() => markAttendance('Absent')}
                            disabled={submitting}
                            className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-red-600 hover:bg-red-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-red-500 disabled:bg-red-400"
                        >
                            <XCircle className="-ml-1 mr-2 h-5 w-5" />
                            Mark Absent
                        </button>
                    </div>
                </div>
            </div>

            <div>
                <h3 className="text-lg font-medium leading-6 text-gray-900 mb-4">Attendance History</h3>
                <div className="bg-white shadow overflow-hidden sm:rounded-md ring-1 ring-gray-200">
                    <ul className="divide-y divide-gray-200">
                        {attendanceList.length === 0 ? (
                            <li className="px-4 py-4 sm:px-6 text-center text-gray-500">No attendance records found.</li>
                        ) : attendanceList.sort((a,b) => new Date(b.date) - new Date(a.date)).map((record) => (
                            <li key={record.id}>
                                <div className="px-4 py-4 sm:px-6 flex items-center justify-between">
                                    <p className="text-sm font-medium text-blue-600 truncate">{record.date}</p>
                                    <div className="ml-2 flex-shrink-0 flex">
                                        <p className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${record.status === 'Present' ? 'bg-green-100 text-green-800 border border-green-200' : 'bg-red-100 text-red-800 border border-red-200'}`}>
                                            {record.status}
                                        </p>
                                    </div>
                                </div>
                            </li>
                        ))}
                    </ul>
                </div>
            </div>
        </div>
    );
};

export default Attendance;
